#include "interface.h"
#include <yyjson.h>
#include <cstdlib>
#include <string>
#include <vector>

std::string build_json(
    const std::vector<uint32_t>& ids,
    const std::vector<uint32_t>& values,
    const std::vector<std::string>& names) {
    yyjson_mut_doc *doc = yyjson_mut_doc_new();
    yyjson_mut_val *arr = yyjson_mut_arr_with_capacity(doc, ids.size());

    for (size_t i = 0; i < ids.size(); ++i) {
        yyjson_mut_val *obj = yyjson_mut_obj_with_capacity(doc, 4);
        yyjson_mut_obj_add_uint(doc, obj, "id", static_cast<uint64_t>(ids[i]));
        yyjson_mut_obj_add_bool(doc, obj, "flag", (ids[i] % 3U) == 0U);
        yyjson_mut_obj_add_uint(doc, obj, "value", static_cast<uint64_t>(values[i]));
        yyjson_mut_obj_add_strn(doc, obj, "name", names[i].c_str(), names[i].size());
        yyjson_mut_arr_append(arr, obj);
    }

    yyjson_mut_doc_set_root(doc, arr);

    size_t len = 0;
    char *json_cstr = yyjson_mut_write(doc, 0, &len);
    std::string result(json_cstr, len);
    free(json_cstr);
    yyjson_mut_doc_free(doc);
    return result;
}
